import React, { useEffect, useMemo, useRef, useState } from 'react';
import axios from 'axios';
import L from 'leaflet';
import { MapContainer as LeafletMap, TileLayer, Circle, Marker, Polyline, useMapEvents } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import markerIcon2x from 'leaflet/dist/images/marker-icon-2x.png';
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';
import { formatTimeAgo } from '../lib/time';
import ReportModal from './ReportModal';
import ReportSidebar from './ReportSidebar';

L.Icon.Default.mergeOptions({
  iconRetinaUrl: markerIcon2x,
  iconUrl: markerIcon,
  shadowUrl: markerShadow,
});

const DEFAULT_CENTER = { lat: 17.385, lng: 78.4867 };

function toLatLngLiteral(report) {
  const lat = Number(report?.lat);
  const lng = Number(report?.lng);
  if (Number.isFinite(lat) && Number.isFinite(lng)) return { lat, lng };

  const coords = report?.location?.coordinates;
  if (Array.isArray(coords) && coords.length === 2) {
    const [cLng, cLat] = coords;
    if (Number.isFinite(cLat) && Number.isFinite(cLng)) return { lat: cLat, lng: cLng };
  }
  return null;
}

function normalizeLevel(value) {
  const v = String(value || '').trim().toLowerCase();
  if (!v) return null;
  if (v === 'low') return 'Low';
  if (v === 'medium') return 'Medium';
  if (v === 'high') return 'High';

  if (v === 'ankle' || v === 'ankle level') return 'Low';
  if (v === 'knee' || v === 'knee level') return 'Medium';
  if (v === 'vehicle risk' || v === 'vehicle_risk' || v === 'vehiclerisk') return 'High';
  return null;
}

function levelStyle(level) {
  const v = normalizeLevel(level);
  if (v === 'High') return { stroke: '#ff3b30', fill: '#ff3b30', radius: 500 };
  if (v === 'Medium') return { stroke: '#facc15', fill: '#facc15', radius: 350 };
  return { stroke: '#34d399', fill: '#34d399', radius: 220 };
}

function haversineMeters(a, b) {
  const toRad = (x) => (x * Math.PI) / 180;
  const R = 6371000;
  const dLat = toRad(b.lat - a.lat);
  const dLng = toRad(b.lng - a.lng);
  const lat1 = toRad(a.lat);
  const lat2 = toRad(b.lat);
  const s =
    Math.sin(dLat / 2) ** 2 + Math.cos(lat1) * Math.cos(lat2) * Math.sin(dLng / 2) ** 2;
  return 2 * R * Math.asin(Math.min(1, Math.sqrt(s)));
}

function parseLatLng(text) {
  const v = String(text || '').trim();
  const m = v.match(/^\s*(-?\d+(\.\d+)?)\s*,\s*(-?\d+(\.\d+)?)\s*$/);
  if (!m) return null;
  const lat = Number(m[1]);
  const lng = Number(m[3]);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  return { lat, lng };
}

async function geocodeNominatim(query) {
  const q = String(query || '').trim();
  if (!q) return null;
  const url = `https://nominatim.openstreetmap.org/search?format=json&limit=1&q=${encodeURIComponent(
    q
  )}`;
  const res = await fetch(url, {
    headers: {
      Accept: 'application/json',
    },
  });
  if (!res.ok) return null;
  const data = await res.json();
  const first = Array.isArray(data) ? data[0] : null;
  const lat = Number(first?.lat);
  const lng = Number(first?.lon);
  if (!Number.isFinite(lat) || !Number.isFinite(lng)) return null;
  return { lat, lng };
}

function MapClickHandler({ onClick }) {
  useMapEvents({
    click(e) {
      onClick?.({ lat: e.latlng.lat, lng: e.latlng.lng });
    },
  });
  return null;
}

export default function MapContainerOsm({
  apiBaseUrl = 'http://localhost:5000',
  auth,
  defaultOpenReportModal = false,
  onExit,
  onLogout,
}) {
  const mapRef = useRef(null);

  const [reports, setReports] = useState([]);
  const [loadingReports, setLoadingReports] = useState(true);
  const [placeCache, setPlaceCache] = useState({});

  const [destination, setDestination] = useState('');
  const [routeStatus, setRouteStatus] = useState('');
  const [routeLine, setRouteLine] = useState(null); // array of [lat,lng]

  const [reportModalOpen, setReportModalOpen] = useState(defaultOpenReportModal);
  const [reportSubmitting, setReportSubmitting] = useState(false);
  const [selectedLocation, setSelectedLocation] = useState(null);
  const [originLocation, setOriginLocation] = useState(null);
  const [selectingDestination, setSelectingDestination] = useState(false);
  const [destinationLatLng, setDestinationLatLng] = useState(null);

  const axiosClient = useMemo(() => {
    const instance = axios.create({ baseURL: apiBaseUrl });
    if (auth?.token) {
      instance.interceptors.request.use((config) => {
        config.headers = config.headers || {};
        config.headers.Authorization = `Bearer ${auth.token}`;
        return config;
      });
    }
    return instance;
  }, [apiBaseUrl, auth?.token]);

  const enrichedReports = useMemo(() => {
    return reports.map((r) => {
      const id = r._id || `${r.lat}-${r.lng}-${r.createdAt || r.timestamp || r.time}`;
      const ts = r.createdAt || r.timestamp || r.time;
      return {
        ...r,
        _listId: id,
        timeAgo: formatTimeAgo(ts),
        placeName: placeCache[id] || r.address || '',
      };
    });
  }, [placeCache, reports]);

  useEffect(() => {
    let cancelled = false;
    setLoadingReports(true);
    axiosClient
      .get('/api/reports/active')
      .then((res) => {
        if (!cancelled) setReports(res.data || []);
      })
      .catch(() => {
        if (!cancelled) setReports([]);
      })
      .finally(() => {
        if (!cancelled) setLoadingReports(false);
      });
    return () => {
      cancelled = true;
    };
  }, [axiosClient]);

  useEffect(() => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const ll = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setOriginLocation(ll);
        setSelectedLocation(ll);
        mapRef.current?.setView([ll.lat, ll.lng], 13);
      },
      () => {}
    );
  }, []);

  const findSafeRoute = async () => {
    if (!originLocation) {
      setRouteStatus('Current location not available (allow location permission).');
      return;
    }
    if (!destination.trim() && !destinationLatLng) {
      setRouteStatus('Enter destination or click the map to set destination.');
      return;
    }

    setRouteLine(null);
    setRouteStatus('Calculating route...');

    let dest = destinationLatLng || parseLatLng(destination);
    if (!dest) {
      try {
        dest = await geocodeNominatim(destination);
      } catch {
        dest = null;
      }
    }

    if (!dest) {
      setRouteStatus('Destination not found. Try "lat,lng" or click map to pick destination.');
      return;
    }

    const zones = enrichedReports
      .map((r) => {
        const ll = toLatLngLiteral(r);
        if (!ll) return null;
        const style = levelStyle(r.waterLevel || r.intensity);
        const level = normalizeLevel(r.waterLevel || r.intensity);
        if (level !== 'High' && level !== 'Medium') return null;
        return { center: ll, radius: style.radius, level };
      })
      .filter(Boolean);

    const intersectsZones = (geojsonLineCoords) => {
      // coords: [[lng,lat], ...]
      for (const c of geojsonLineCoords || []) {
        const p = { lat: c[1], lng: c[0] };
        for (const z of zones) {
          if (haversineMeters(p, z.center) <= z.radius) return true;
        }
      }
      return false;
    };

    const url = `https://router.project-osrm.org/route/v1/driving/${originLocation.lng},${originLocation.lat};${dest.lng},${dest.lat}?overview=full&geometries=geojson&alternatives=true`;

    try {
      const res = await fetch(url);
      const data = await res.json();
      const routes = Array.isArray(data?.routes) ? data.routes : [];
      if (!routes.length) {
        setRouteStatus('Routing failed. Try a different destination.');
        return;
      }

      let chosen = routes[0];
      let foundSafe = false;
      for (const r of routes) {
        const coords = r?.geometry?.coordinates || [];
        if (!intersectsZones(coords)) {
          chosen = r;
          foundSafe = true;
          break;
        }
      }

      const coords = chosen?.geometry?.coordinates || [];
      const line = coords.map((c) => [c[1], c[0]]);
      setRouteLine(line);
      setRouteStatus(
        foundSafe
          ? 'Route ready.'
          : 'Flood warning: all available routes intersect Medium/High flood zones.'
      );
      mapRef.current?.fitBounds(L.latLngBounds(line), { padding: [32, 32] });
    } catch {
      setRouteStatus(
        'Routing failed. If you are offline or OSRM is blocked, try again later.'
      );
    }
  };

  const detectLocation = () => {
    if (!navigator.geolocation) return;
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const ll = { lat: pos.coords.latitude, lng: pos.coords.longitude };
        setOriginLocation(ll);
        setSelectedLocation(ll);
        mapRef.current?.setView([ll.lat, ll.lng], 13);
      },
      () => {}
    );
  };

  const submitReport = async ({ waterLevel, file }) => {
    if (!selectedLocation) return;
    setReportSubmitting(true);
    try {
      if (file) {
        const form = new FormData();
        form.append('waterLevel', waterLevel);
        form.append('lat', String(selectedLocation.lat));
        form.append('lng', String(selectedLocation.lng));
        form.append('image', file);
        await axiosClient.post(`/api/reports`, form);
      } else {
        await axiosClient.post(`/api/reports`, {
          waterLevel,
          lat: selectedLocation.lat,
          lng: selectedLocation.lng,
        });
      }

      const res = await axiosClient.get(`/api/reports/active`);
      setReports(res.data || []);
      setReportModalOpen(false);
    } catch (e) {
      setRouteStatus(e?.response?.data?.msg || 'Report submit failed');
    } finally {
      setReportSubmitting(false);
    }
  };

  useEffect(() => {
    if (defaultOpenReportModal) setReportModalOpen(true);
  }, [defaultOpenReportModal]);

  const onMapClick = (ll) => {
    if (selectingDestination) {
      setDestinationLatLng(ll);
      setDestination(`${ll.lat.toFixed(6)},${ll.lng.toFixed(6)}`);
      setSelectingDestination(false);
      setRouteStatus('Destination set. Click "Find Safe Route".');
      return;
    }
    setSelectedLocation(ll);
  };

  return (
    <div className="relative h-[calc(100vh-3.5rem)] w-full overflow-hidden">
      <LeafletMap
        center={[DEFAULT_CENTER.lat, DEFAULT_CENTER.lng]}
        zoom={11}
        style={{ height: '100%', width: '100%' }}
        whenCreated={(m) => {
          mapRef.current = m;
        }}
      >
        <TileLayer
          attribution='&copy; OpenStreetMap contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        <MapClickHandler onClick={onMapClick} />

        {originLocation ? <Marker position={[originLocation.lat, originLocation.lng]} /> : null}
        {selectedLocation ? <Marker position={[selectedLocation.lat, selectedLocation.lng]} /> : null}
        {destinationLatLng ? <Marker position={[destinationLatLng.lat, destinationLatLng.lng]} /> : null}

        {enrichedReports.map((r) => {
          const ll = toLatLngLiteral(r);
          if (!ll) return null;
          const style = levelStyle(r.waterLevel || r.intensity);
          return (
            <Circle
              key={r._listId || r._id}
              center={[ll.lat, ll.lng]}
              radius={style.radius}
              pathOptions={{ color: style.stroke, fillColor: style.fill, fillOpacity: 0.22, weight: 2 }}
            />
          );
        })}

        {routeLine?.length ? (
          <Polyline pathOptions={{ color: '#2d9cdb', weight: 5, opacity: 0.95 }} positions={routeLine} />
        ) : null}
      </LeafletMap>

      <div className="pointer-events-none absolute inset-0 z-[1200]">
        <div className="pointer-events-auto absolute left-4 top-4">
          <ReportSidebar
            reports={enrichedReports}
            loading={loadingReports}
            onPickReport={(r) => {
              const ll = toLatLngLiteral(r);
              if (!ll || !mapRef.current) return;
              mapRef.current.setView([ll.lat, ll.lng], 14);
            }}
            onOpenReport={() => setReportModalOpen(true)}
            routing={{
              origin: originLocation ? 'Current location' : '',
              setOrigin: () => {},
              originReadOnly: true,
              destination,
              setDestination: (v) => {
                setDestination(v);
                setDestinationLatLng(parseLatLng(v));
              },
              onFindRoute: findSafeRoute,
              enabled: true,
              status: routeStatus,
            }}
          />

          <div className="mt-3 flex flex-wrap gap-2">
            <button
              type="button"
              onClick={detectLocation}
              className="rounded-2xl border border-white/10 bg-white/5 px-3 py-2 text-xs font-semibold text-slate-100 hover:bg-white/10"
            >
              Re-detect Location
            </button>
            <button
              type="button"
              onClick={() => {
                setSelectingDestination(true);
                setRouteStatus('Click on the map to set destination.');
              }}
              className="rounded-2xl border border-white/10 bg-white/5 px-3 py-2 text-xs font-semibold text-slate-100 hover:bg-white/10"
            >
              Pick Destination
            </button>
            <button
              type="button"
              onClick={() => onExit?.()}
              className="rounded-2xl border border-white/10 bg-white/5 px-3 py-2 text-xs font-semibold text-slate-100 hover:bg-white/10"
            >
              Back
            </button>
            <button
              type="button"
              onClick={() => onLogout?.()}
              className="rounded-2xl border border-white/10 bg-white/5 px-3 py-2 text-xs font-semibold text-slate-100 hover:bg-white/10"
            >
              Logout
            </button>
          </div>
        </div>

        <div className="pointer-events-auto absolute right-4 top-4 rounded-2xl border border-white/10 bg-slate-950/75 px-3 py-2 text-xs text-slate-300 shadow-soft backdrop-blur">
          {selectingDestination ? 'Click map to set destination' : 'Click map to set report location'}
        </div>
      </div>

      <ReportModal
        open={reportModalOpen}
        onClose={() => setReportModalOpen(false)}
        onSubmit={submitReport}
        location={selectedLocation}
        onDetectLocation={detectLocation}
        submitting={reportSubmitting}
      />
    </div>
  );
}
